unitsize(0.5 cm);

pair A, B, O;

A = 3*dir(100);
B = 9*dir(10);
O = (0,0);

draw(A--O--B--cycle);

draw((-2,0)--(10,0));
draw((0,-1)--(0,4));

label("$A$", A, NW);
label("$B$", B, E);
label("$O$", O, SW);
[/asy]

